func testAccChronicleNativeDashboard_chronicleNativedashboardBasicExample(context map[string]interface{}) string {
	return acctest.Nprintf(`
resource "google_chronicle_native_dashboard" "my_basic_dashboard" {
  location     = "us"
  instance     = "%{chronicle_id}"
  display_name = "%{dashboard_name}"
  description  = "%{dashboard_description}"
  access       = "DASHBOARD_PRIVATE"
  type         = "CUSTOM"

  filters {
    id                                    = "GlobalTimeFilter"
    display_name                          = "Global Time Filter"
    data_source                           = "GLOBAL"
    is_standard_time_range_filter         = true
    is_standard_time_range_filter_enabled = true
    filter_operator_and_field_values {
      filter_operator = "PAST"
      field_values    = ["1", "DAY"]
    }
  }
}
`, context)
}

func testAccCheckChronicleNativeDashboardDestroyProducer(t *testing.T) func(s *terraform.State) error {
	return func(s *terraform.State) error {
		for name, rs := range s.RootModule().Resources {
			if rs.Type != "google_chronicle_native_dashboard" {
				continue
			}
			if strings.HasPrefix(name, "data.") {
				continue
			}

			config := acctest.GoogleProviderConfig(t)
			url, err := tpgresource.ReplaceVarsForTest(config, rs, transport_tpg.BaseUrl(chronicle.Product, config)+"projects/{{project}}/locations/{{location}}/instances/{{instance}}/nativeDashboards/{{dashboard_id}}")
			if err != nil {
				return err
			}

			billingProject := ""

			if config.BillingProject != "" {
				billingProject = config.BillingProject
			}

			_, err = transport_tpg.SendRequest(transport_tpg.SendRequestOptions{
				Config:    config,
				Method:    "GET",
				Project:   billingProject,
				RawURL:    url,
				UserAgent: config.UserAgent,
			})
			if err == nil {
				return fmt.Errorf("ChronicleNativeDashboard still exists at %s", url)
			}
		}

		return nil
	}
}
